'use client';

import { useEffect, useMemo, useState } from 'react';
import type { VocabularyWordStatus } from '@soenglish/shared-types';
import { PageHeader } from '../../components/ui';
import {
  activeAccount,
  activeMockUser,
  canEdit,
  canView,
  joinProfileVocabulary,
  siteContent,
  updateProfileVocabularyStatus,
} from '../../mocks';
import { VocabularyFlashcardSection, VocabularyListSection, VocabularyModeToggle, VocabularyStatsRow } from './sections';
import styles from './page.module.scss';

export default function VocabularyPage() {
  if (!canView('vocabulary', activeMockUser.role)) return null;
  const canSetKnown = activeMockUser.role !== 'student';

  const [items, setItems] = useState(() =>
    joinProfileVocabulary(activeAccount.id, activeMockUser.id),
  );
  const refreshItems = () =>
    setItems(joinProfileVocabulary(activeAccount.id, activeMockUser.id));

  const applyStatus = (entryId: string, status: VocabularyWordStatus) => {
    if (!canSetKnown && status === 'known') return;
    updateProfileVocabularyStatus(entryId, status);
    refreshItems();
  };

  const [filter, setFilter] = useState('All');
  const [statusFilter, setStatusFilter] = useState('all');
  const [mode, setMode] = useState<'list' | 'flashcard'>('list');
  const [cardIndex, setCardIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [search, setSearch] = useState('');
  const categories = useMemo(() => {
    const unique = [...new Set(items.map(({ word }) => word.category))].sort((a, b) =>
      a.localeCompare(b),
    );
    return ['All', ...unique];
  }, [items]);

  useEffect(() => {
    if (!categories.includes(filter)) setFilter('All');
  }, [categories, filter]);

  const filtered = useMemo(
    () =>
      items.filter(({ row, word }) => {
        const catOk = filter === 'All' || word.category === filter;
        const statusOk = statusFilter === 'all' || row.status === statusFilter;
        const searchOk =
          !search ||
          word.word.toLowerCase().includes(search.toLowerCase()) ||
          word.definition.toLowerCase().includes(search.toLowerCase());
        return catOk && statusOk && searchOk;
      }),
    [items, filter, statusFilter, search],
  );

  const currentItem = filtered[cardIndex];
  const markStatus = (status: VocabularyWordStatus) => {
    if (!currentItem) return;
    if (!canSetKnown && status === 'known') return;
    applyStatus(currentItem.row.id, status);
    setFlipped(false);
    setTimeout(() => setCardIndex((i) => Math.min(i + 1, Math.max(0, filtered.length - 1))), 300);
  };

  const stats = {
    new: items.filter(({ row }) => row.status === 'new').length,
    learning: items.filter(({ row }) => row.status === 'learning').length,
    known: items.filter(({ row }) => row.status === 'known').length,
  };

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        textClassName={styles.pageHeaderText}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title={`${siteContent.vocabulary.title}${canEdit('vocabulary', activeMockUser.role) ? '' : ' (read only)'}`}
        subtitle={`${items.length} words in your library`}
        actions={<VocabularyModeToggle mode={mode} onChange={(nextMode) => { setMode(nextMode); if (nextMode === 'flashcard') { setCardIndex(0); setFlipped(false); } }} />}
      />

      <VocabularyStatsRow total={items.length} stats={stats} onFilter={setStatusFilter} />

      {mode === 'list' && (
        <VocabularyListSection
          search={search}
          setSearch={setSearch}
          categories={categories}
          filter={filter}
          setFilter={setFilter}
          filtered={filtered}
          onSetStatus={applyStatus}
          canSetKnown={canSetKnown}
          totalSourceCount={items.length}
        />
      )}

      {mode === 'flashcard' && (
        <VocabularyFlashcardSection
          cardIndex={cardIndex}
          total={filtered.length}
          currentItem={currentItem}
          flipped={flipped}
          setFlipped={setFlipped}
          markStatus={markStatus}
          setCardIndex={setCardIndex}
          canSetKnown={canSetKnown}
        />
      )}
    </div>
  );
}
